SELECT CODE_GROUP, CODE_GROUP_NAME, USE_YN 
  FROM COME_CODE_GROUP
  WHERE 1 = 1

   AND CODE_GROUP = #{groupCode}


   AND USE_YN = #{useYn}

SELECT CODE_GROUP, CODE_VALUE, CODE_NAME, UP_CODE_CODE , SORT_ORDER, CODE_PROP, CODE_EXP, USE_YN FROM COM_CODE WHERE 1 = 1
AND CODE_GROUP = #{groupCode}
AND USE_YN = 'Y'

SELECT CODE_GROUP, CODE_GROUP_NAME, USE_YN 
  FROM COME_CODE_GROUP
  WHERE 1 = 1

   AND CODE_GROUP = #{groupCode}


   AND USE_YN = #{useYn}

SELECT CODE_GROUP, CODE_GROUP_NAME, USE_YN 
  FROM COME_CODE_GROUP
  WHERE 1 = 1

   AND CODE_GROUP = #{groupCode}


   AND USE_YN = #{useYn}

SELECT CODE_GROUP, CODE_VALUE, CODE_NAME, UP_CODE_CODE 
	 , SORT_ORDER, CODE_PROP, CODE_EXP, USE_YN
  FROM COM_CODE
 WHERE 1 = 1

   AND CODE_GROUP = #{groupCode}


   AND CODE_VALUE = #{codeValue}


   AND USE_YN = #{useYn}

  ORDER BY CODE_GROUP, SORT_ORDER

SELECT CODE_GROUP, CODE_VALUE, CODE_NAME, UP_CODE_CODE , SORT_ORDER, CODE_PROP, CODE_EXP, USE_YN FROM COM_CODE WHERE 1 = 1
AND CODE_GROUP = #{groupCode}
AND USE_YN = #{useYn}
ORDER BY CODE_GROUP, SORT_ORDER

SELECT ROWNUM AS SEQ , CODE_GROUP, CODE_VALUE, CODE_NAME, UP_CODE_CODE , SORT_ORDER, CODE_PROP, CODE_EXP, USE_YN , MAX_CNT , CEIL(MAX_CNT / #{pagePerRow} ) AS TOTAL_PAGE FROM ( SELECT CODE_GROUP, CODE_VALUE, CODE_NAME, UP_CODE_CODE , SORT_ORDER, CODE_PROP, CODE_EXP, USE_YN , COUNT(*) OVER() AS MAX_CNT FROM COM_CODE WHERE 1 = 1
AND CODE_GROUP = #{groupCode}
AND USE_YN = #{useYn}
ORDER BY SORT_ORDER DESC ) OFFSET (#{pageNum} - 1) * #{pagePerRow} ROWS FETCH NEXT #{pagePerRow} ROWS ONLY
